mapper.select:
/* com.erns.coching.board.mapper.BoardDAO.getList */
SELECT ZZ.* FROM ( SELECT
, COALESCE( (SELECT COUNT(*) FROM T_BOARD_CMT BC WHERE AA.BOARD_SEQ = BC.BOARD_SEQ AND BC.DEL_YN = 'N') , 0 ) AS CMT_CNT /* 코멘트 갯수 */ , MEMB.NICKNAME AS REG_NAME , MEMB.MEMB_ID AS REG_ID FROM T_BOARD_INF AA LEFT JOIN T_MEMB_INF MEMB /* 작성자 정보 */ ON AA.RGTR = MEMB.MEMB_SEQ
ORDER BY AA.BOARD_SEQ DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.board.mapper.BoardDAO.load */

SELECT

	, AA.CONTENT
FROM T_BOARD_INF AA			

	AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.loadDetail */
SELECT
, AA.CONTENT , BB.BOARD_NAME , MEMB.NICKNAME AS REG_NAME , MEMB.MEMB_ID AS REG_ID , (SELECT COUNT(*) FROM T_BOARD_CMT WHERE BOARD_SEQ = #{boardSeq, jdbcType=INTEGER} AND DEL_YN = 'N' ) AS CMT_CNT , CC.CMT_USE_YN FROM T_BOARD_INF AA LEFT JOIN T_BOARD_MST BB ON AA.BOARD_MST_ID = BB.BOARD_MST_ID LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ LEFT JOIN T_BOARD_OPT CC ON AA.BOARD_MST_ID = CC.BOARD_MST_ID
AND AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR} AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.board.mapper.BoardDAO.insert */


	SELECT nextval('seq_t_board_inf')


INSERT INTO T_BOARD_INF (
		BOARD_SEQ
	, BOARD_MST_ID
	, CATE_CD
	, TITLE
	, CONTENT
	, WRITER
	, SORT_ORD
	, DEL_YN
	, VIEWS
	, FROM_DATE
	, TO_DATE
	, FIX_YN

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
		#{boardSeq		, jdbcType=INTEGER}
	, #{boardMstId	, jdbcType=VARCHAR}
	, #{cateCd			, jdbcType=VARCHAR}
	, #{title				, jdbcType=VARCHAR}
	, #{content			, jdbcType=VARCHAR}
	, #{writer			, jdbcType=VARCHAR}
	, #{sortOrd			, jdbcType=INTEGER}
	, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
	, COALESCE(#{views	, jdbcType=INTEGER}, 0)
	, #{fromDate		, jdbcType=VARCHAR}
	, #{toDate			, jdbcType=VARCHAR}
	, COALESCE(#{fixYn	, jdbcType=CHAR}, 'N')

	, #{rgtr		, jdbcType=INTEGER}
	, now()
	, #{chnr		, jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.coching.board.mapper.BoardDAO.update */

UPDATE T_BOARD_INF SET
		CATE_CD       = #{cateCd		, jdbcType=VARCHAR}
	, TITLE         = #{title		, jdbcType=VARCHAR}
	, CONTENT       = #{content		, jdbcType=VARCHAR}
	, WRITER        = #{writer		, jdbcType=VARCHAR}
	, FROM_DATE     = #{fromDate	, jdbcType=VARCHAR}
	, TO_DATE       = #{toDate		, jdbcType=VARCHAR}
	, FIX_YN        = COALESCE(#{fixYn	, jdbcType=CHAR}, 'N')

	, CHNR 					= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM			= now()

	AND BOARD_SEQ 	= #{boardSeq	, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.updateViewCnt */

UPDATE T_BOARD_INF SET
	VIEWS 		= VIEWS + 1

	AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

		/* com.erns.coching.board.mapper.BoardDAO.updateDelYn */

		UPDATE T_BOARD_INF SET
    	  DEL_YN 			= #{delYn	, jdbcType=CHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.board.mapper.BoardDAO.delete */

DELETE FROM T_BOARD_INF

	AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.board.mapper.BoardDAO.getInqrList */
SELECT ZZ.* FROM ( SELECT
, CASE WHEN (SELECT COUNT(*) FROM T_INQUIRY_INF WHERE ORG_SEQ = AA.BOARD_SEQ) > 0 THEN 'Y' ELSE 'N' END AS IS_REPLY , MEMB.NICKNAME AS REG_NAME , MEMB.MEMB_ID AS REG_ID FROM T_INQUIRY_INF AA LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ WHERE AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N'
ORDER BY AA.BOARD_SEQ DESC ) ZZ
AND ZZ.IS_REPLY = #{isReply, jdbcType=VARCHAR}
OFFSET #{offset} LIMIT #{rowSize}

mapper.insert:
/* com.erns.coching.board.mapper.BoardDAO.insertInqr */


	SELECT nextval('seq_t_inquiry_inf')


INSERT INTO T_INQUIRY_INF (
	  BOARD_SEQ
	, BOARD_MST_ID
	, CATE_CD
	, TITLE
	, CONTENT
	, WRITER
	, PHONE
	, EMAIL
	, ORG_SEQ
	, SORT_ORD
	, DEL_YN
	, ADMIN_DEL_CD
	, ADMIN_DEL_RSN
	, VIEWS
	, FROM_DATE
	, TO_DATE
	, FIX_YN
	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
	  #{boardSeq       , jdbcType=INTEGER}
	, #{boardMstId     , jdbcType=VARCHAR}
	, #{cateCd         , jdbcType=VARCHAR}
	, #{title          , jdbcType=VARCHAR}
	, #{content        , jdbcType=VARCHAR}
	, #{writer         , jdbcType=VARCHAR}
	, #{phone          , jdbcType=VARCHAR}
	, #{email          , jdbcType=VARCHAR}
	, COALESCE(#{orgSeq , jdbcType=INTEGER}, 0)
	, #{sortOrd        , jdbcType=INTEGER}
	, COALESCE(#{delYn , jdbcType=CHAR}, 'N')
	, #{adminDelCd     , jdbcType=VARCHAR}
	, #{adminDelRsn    , jdbcType=VARCHAR}
	, COALESCE(#{views , jdbcType=INTEGER}, 0)
	, #{fromDate       , jdbcType=VARCHAR}
	, #{toDate         , jdbcType=VARCHAR}
	, COALESCE(#{fixYn , jdbcType=CHAR}, 'N')
	, #{rgtr           , jdbcType=INTEGER}
	, now()
	, #{chnr           , jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.coching.board.mapper.BoardDAO.updateInqr */

UPDATE T_INQUIRY_INF SET
	TITLE         = #{title		, jdbcType=VARCHAR}
	, CONTENT       = #{content		, jdbcType=VARCHAR}

	, CHNR 					= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM			= now()

	AND BOARD_SEQ 	= #{boardSeq	, jdbcType=INTEGER}

		/* com.erns.coching.board.mapper.BoardDAO.updateInqrDelYn */

		UPDATE T_INQUIRY_INF SET
    	  DEL_YN 			= #{delYn	, jdbcType=CHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.board.mapper.BoardDAO.loadInqrDetail */
SELECT AA.* , ( SELECT MIN(AA.BOARD_SEQ) FROM T_INQUIRY_INF AA WHERE AA.BOARD_SEQ > #{boardSeq, jdbcType=INTEGER} AND AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N' ) AS NEXT , ( SELECT MAX(AA.BOARD_SEQ) FROM T_INQUIRY_INF AA WHERE AA.BOARD_SEQ < #{boardSeq, jdbcType=INTEGER} AND AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N' ) AS PREV , CD.CODE_NAME AS CATE_NM , MEMB.NICKNAME AS REG_NAME , MEMB.MEMB_ID AS REG_ID , CASE WHEN (SELECT COUNT(*) FROM T_INQUIRY_INF WHERE ORG_SEQ = AA.BOARD_SEQ) > 0 THEN 'Y' ELSE 'N' END AS IS_REPLY FROM T_INQUIRY_INF AA LEFT JOIN T_CODE_INF CD ON AA.CATE_CD = CD.ETC1 AND CD.GRP_CODE = 'CH015' AND CD.ETC5 = UPPER(#{locale, jdbcType=VARCHAR}) LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ
AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.loadInqrReply */

SELECT *
	FROM T_INQUIRY_INF AA

	AND AA.ORG_SEQ = #{boardSeq, jdbcType=INTEGER}
